var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"충성. 오랜만입니다, 대통령님.","JPN":"敬礼。ご無沙汰しております、大統領閣下。","ENG":"Hello, Mister President. It’s been a long time.","TWN":"忠誠！總統好久不見。"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"……이거 놀랍군. 자네가 먼저 연락을 하다니.","JPN":"……これは驚いたな。君から連絡が来るとは。","ENG":"My... It's a surprise. I never expected you to call first.","TWN":"……真是意外，你竟然會主動跟我聯絡。"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"목소리 듣기도 어려웠던 사람이 무슨 바람이 분 건가?","JPN":"声も滅多に聞けない者がどういう風の吹き回しだ。","ENG":"Considering how rarely you call, to what do I owe this pleasure?","TWN":"平常光是要聽到你的聲音都很難，是什麼風把你吹來的？"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"자주 인사드리지 못한 건 사과드리겠습니다.","JPN":"頻繁にご連絡できなかったことはお詫び申し上げます。","ENG":"I apologize for not being able to contact you more often.","TWN":"很抱歉，久久才向總統問安。"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하지만 저와 자주 연락하시는 게 정치적으로 좋은 일은 아니란 걸 모르시진 않겠죠.","JPN":"ですが、私とたびたび連絡をとるのが政治的によくないということはご存じではありませんか。","ENG":"However, you must be aware that my contacting you frequently does not look good from a political standpoint.","TWN":"但我想總統也很清楚，太常和我聯絡，就政治層面而言並非好事。"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"제 나름대로의 배려였다고 생각해 주시면 감사하겠습니다.","JPN":"私なりの気遣いだったとお考えください。","ENG":"Please consider it an act of consideration on my part.","TWN":"就當作是我自以為的體貼吧，還請見諒。"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"좋아. 틀린 말은 아니지.","JPN":"いいだろう。間違ってはいない。","ENG":"I understand. You aren’t wrong about that.","TWN":"好吧，你說的也有道理。"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"그래서 오늘은 무슨 일인가?","JPN":"で、今日はどうした？","ENG":"So, what did you call me for?","TWN":"所以到底是什麼事？"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"저도 대통령님의 간접적인 화법에 맞춰드리고 싶지만 그럴 여유가 없군요.","JPN":"私も大統領閣下の間接的な話し方にお付き合いしたいところですが、その余裕はございません。","ENG":"I would have preferred to approach this with you in a gentler manner, but I am unfortunately out of time.","TWN":"我也想配合總統先寒暄幾句，但情況有點緊急。"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"단도직입적으로 말씀드리죠. 감찰부대가 제가 있는 기지를 공격하고 있습니다.","JPN":"単刀直入にお話しいたします。監察部隊が私のいる基地を攻撃しています。","ENG":"So I’ll get straight to the point. The Inspection Corps are currently attacking my base.","TWN":"請恕我就直接進入主題，監察組正在攻擊我所在的基地。"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"뭐라고……?","JPN":"何だと……？","ENG":"What...?!","TWN":"你說什麼……？"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"국방부 네트워크의 제 ID도 접근이 차단됐군요.","JPN":"私の国防省ネットワークのIDもアクセスが拒否されています。","ENG":"I have also found that my ID has lost access to the National Defense network.","TWN":"而且國防部的網路也已經封鎖我的帳號，"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"아마도 제가 국가의 적으로 규정된 모양입니다.","JPN":"たぶん私を国家の敵と規定したのでしょう。","ENG":"It seems that I have been designated as an enemy of the state.","TWN":"看來我已經被判定是國家的敵人。"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"말도 안되는 소리, 자네가 국가의 적이 될 리가 없잖나?","JPN":"あり得ない、君が国家の敵のはずがないだろう？","ENG":"That’s outrageous! There’s no way that you would be an enemy of the state!","TWN":"荒謬！你怎麼可能會是國家的敵人？！"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그렇지 않으면 국가의 적일 가능성이 있다고 의심 받았다, 정도로 해 두죠.","JPN":"それでは国家の敵である可能性を疑われたとでもしておきましょう。","ENG":"Or, alternatively, I could be under suspicion of being a potential enemy of the state.","TWN":"要不就先假設我被懷疑有可能成為國家的敵人吧。"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"명분이야 어쨌든, 지금 제 발을 묶고 시간을 낭비하게만 하면 저들을 움직인 자들의 목적은 충분히 달성될 테니까요.","JPN":"名分はどうであれ、今私の足を引っ張り、時間さえ無駄にさせれば彼らを動かした者の目的は十分達成するわけですので。","ENG":"Whatever the reason, whoever is behind this will be able to achieve their goal if I allow them to hold me down and waste my time.","TWN":"不管罪名是什麼，現在只要困住我，消耗我們的時間，對方就可以達到他們的目的。"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"대통령님.","JPN":"閣下。","ENG":"Mister President.","TWN":"總統，"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"저는 국민을 지키는 군인으로서 무엇이 되었든 국민의 명령에 복종할 준비가 되어 있습니다.","JPN":"私は国民を守る軍人として、何であろうとも国民の命令に従う準備ができています。","ENG":"As a soldier who serves the people, I am prepared to follow the orders of the people.","TWN":"我身為保護國民的軍人，無論會變成什麼樣，我都已經做好服從國民命令的準備。"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그것이 설령 잘못된 판단과 누명에 의한 것이라고 해도 말이죠.","JPN":"たとえそれが間違った判断と濡れ衣によるものであってもです。","ENG":"Even if such orders are based on faulty judgment and false accusations.","TWN":"就算那是因為錯誤的判斷和栽贓而造成的。"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"……이미 알고 있나 보군.","JPN":"……すでに知っていたようだな。","ENG":"...You seem to be aware already.","TWN":"……看來你很清楚。"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"일부 의원들은 물론이고, 행정부 내에서도 자네에 대한 불만이 많이 나오고 있어.","JPN":"一部の議員はもちろん、行政府からも君への不満が多く出ている。","ENG":"There are many complaints against you coming from not just a few senators, but also from within the administrative office.","TWN":"不只是部分議員，行政院內也有許多人不滿你。"},"stage":{"bg":"DOCUMENTS","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"자의적이고 불필요한 작전 행동에 대한 처벌이 필요하다는 주장도 있지.","JPN":"恣意的かつ不要な作戦行動への処罰が必要だと主張する者もいるぞ。","ENG":"There are even calls for punishment for arbitrary and unnecessary operational activities.","TWN":"也有人主張要針對恣意且不必要的作戰行動進行懲處。"},"stage":{"bg":"DOCUMENTS","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이해합니다. 군대라는 건 아무 소식 없이 조용할 때가 가장 좋은 조직이죠.","JPN":"わかります。軍隊というものは何の便りもなくそのままである時が一番いい組織ですから。","ENG":"I understand. The military is an organization where no news is good news.","TWN":"我明白，所謂的軍隊，就是最好都安靜不要惹事的組織。"},"stage":{"bg":"DOCUMENTS","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"그래. 하지만 감찰부대에 무력 진압을 허가했다는 건 금시초문일세.","JPN":"そうだ。だが、監察部隊に武力の鎮圧を許可したとは聞いたことがないな。","ENG":"That is correct. However, this is the first time that I have been informed about the authorization of the Inspection Corps to use force.","TWN":"嗯嗯，不過監察組對你們武力鎮壓一事，我倒是第一次聽說。"},"stage":{"bg":"DOCUMENTS","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"당장 각료 회의를 소집해서 진상을 규명하겠네.","JPN":"すぐに閣僚会議を招集して真相を確かめよう。","ENG":"I will hold a Cabinet meeting immediately and get down to the bottom of this.","TWN":"我會立刻召開內閣會議查明真相。"},"stage":{"bg":"DOCUMENTS","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"감사합니다, 대통령님.","JPN":"ありがとうございます、閣下。","ENG":"Thank you, Mister President.","TWN":"謝謝總統。"},"stage":{"bg":"DOCUMENTS","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하지만 그래서는 너무 늦습니다.","JPN":"ですが、それでは手遅れになります。","ENG":"However, by the time you are done, it will be too late.","TWN":"不過已經為時已晚。"},"stage":{"bg":"CCN_SHIP","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"자세히 말씀드릴 시간은 없지만, 지금 인류는 매우 큰 위험 앞에 서 있습니다.","JPN":"詳しく説明する時間はありませんが、今人類は非常に危険な状況を目の前にしています。","ENG":"I do not have the time to explain in detail, but humanity is on a knife edge.","TWN":"我沒時間詳細和總統說明，總之現在人類正面臨到巨大的威脅。"},"stage":{"bg":"CCN_SHIP","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"단 한 번이라도 잘못된 결정을 내린다면, 한 순간이라도 대응이 늦는다면 돌이킬 수 없는 일이 벌어질 수 있습니다.","JPN":"たった一度でも間違った判断をすると、一瞬でも対応が遅れると、取り返しのつかないことになりかねません。","ENG":"If even a single wrong decision is made, if we move a moment too late, things may unravel beyond a point of no return.","TWN":"只要一次錯誤的決定，或是一個應變不及，都可能會造成無法挽回憾事。"},"stage":{"bg":"CCN_SHIP","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하지만 저는 군인으로서, 명령이 없다면 움직일 수 없습니다.","JPN":"ですが私は軍人として、命令なしでは動けません。","ENG":"However, I am a soldier, and cannot move without an order.","TWN":"但我身為軍人，若沒有接收到命令就無法行動。"},"stage":{"bg":"CCN_SHIP","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"으음……","JPN":"ううむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"CCN_SHIP","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"이 진압작전이 불법적인 것이라면.","JPN":"この鎮圧作戦が不法であるなら。","ENG":"If this suppression operation is illegal...","TWN":"若這場鎮壓行動是不合法的，"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그리고 제가 국가를 위해 최선의 선택을 할 것을 믿으신다면.","JPN":"そして私が国のため、最善の選択をすると信じてくださるなら。","ENG":"And if you believe that I will make the best decision for this country...","TWN":"若您也相信我會為國家做出最好的決定，"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"국민의 대표로서, 양심과 정의에 따라 제가 해야 할 일을 해야 한다고 판단하신다면……","JPN":"国民の代表として、良心と正義に従い私の役目を果たすべきとご判断なさるのでしたら……","ENG":"As the representative for the people, if you trust that I will do what I must based on my conscience and sense of justice...","TWN":"若您身為國家的統治者，根據良心和正義，認為我該去做我該做的事……"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"명령을 내려 주십시오.","JPN":"ご命令ください。","ENG":"Just say the word, Mister President.","TWN":"就請總統下令吧！"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그렇다면 저와 제 휘하 장병들은 목숨을 걸고 국민의…….","JPN":"そうしてくだされば、私の旗下の将兵は、命をかけて国民の……","ENG":"And my troops and I will give our lives for the people...","TWN":"那麼，我和我的部下將會誓死為國民……"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"아니, 인류의 생명과 존엄을 지키기 위해 싸우겠습니다.","JPN":"いや、人類の生命と尊厳を守るため戦います。","ENG":"No, for all of humanity.","TWN":"不，是為人類的生存和尊嚴而奮戰！"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"대통령님? 괜찮으십니까?","JPN":"閣下？　大丈夫ですか？","ENG":"Mister President? Are you okay?","TWN":"總統？您還好嗎？"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"미안하네. 갑자기 근처에서 폭발이 일어나서 말이지.","JPN":"すまない。近くでいきなり爆発があってな。","ENG":"My apologies, an explosion just occurred nearby.","TWN":"抱歉，周圍突然有爆炸聲。"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"자네가 내게 연락한 걸 알아챈 모양이야. 감찰부대로 추정되는 병력이 여기로 오고 있다고 하네.","JPN":"君が私に連絡したことに気付いたようだ。監察部隊と推測される兵力がこちらへ向かっているという。","ENG":"They seem to have caught on that you are contacting me. I'm getting reports that what appear to be Inspection Corps forces are heading in this direction.","TWN":"看來是有人發現我們通話的事，疑似是監察組的兵力正朝這裡而來。"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"단순한 병력뿐 아니라 침식체로 추정되는 괴생물체들까지 나타났다는군.","JPN":"単なる兵力がだけでなく、侵食体と思われる謎の生物体まで現れたらしい。","ENG":"Not only their regular troops, but also creatures presumed to be Corrupted Objects as well.","TWN":"而且不只是監察組的兵力，還有疑似是侵蝕體的生物。"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"……쿠데타입니까?","JPN":"……クーデターですか？","ENG":"...Is this a coup?","TWN":"……是政變嗎？"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"그런 것 같아. 망할 놈들이 아주 오래전부터 준비해 왔던 모양이야.","JPN":"そのようだ。クソ野郎どもが、結構前から準備してきたようだな。","ENG":"It appears to be so. The bastards must have been planning this for a long time.","TWN":"似乎是，看來那些該死的傢伙是有備而來。"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"이봐, 마리아 중장. 난 정확히 자네가 어떤 적과 싸우고 있는지, 어떤 위기가 다가오는지 모르네.","JPN":"おい、マリア中将。私は君が正確にどのような敵と戦っているのか、どんな危機が迫っているのか知らない。","ENG":"Lieutenant General Antonov. I have no idea exactly what enemy you are fighting, and what danger is approaching.","TWN":"瑪麗亞中將，我不知道你正在和什麼樣的敵人作戰，也不清楚將要面臨的危機是什麼。"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"그리고 자네가 열심히 설명해 주더라도 곧바로 이해할 수는 없겠지.","JPN":"そして君がいくら説明してくれてもすぐには理解できないだろう。","ENG":"Even if you did your best to explain to me in detail, I probably wouldn’t be able to understand right away.","TWN":"就算你努力想解釋給我聽，我也未必能立刻明白。"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"그러니 이것만 묻겠네.","JPN":"だからこれだけ聞こう。","ENG":"Therefore, I will ask just one thing.","TWN":"但我就問你一句。"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"……해낼 수 있겠나?","JPN":"……できるか？","ENG":"...Can you succeed?","TWN":"……打得贏嗎？"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"명예를 걸고, 약속드리겠습니다.","JPN":"私の名誉をかけて、お約束いたします。","ENG":"I swear on my honor that I will prevail.","TWN":"我以軍人的榮譽保證！"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"……그래. 그거면 충분해.","JPN":"……そうか。それで十分だ。","ENG":"...Okay, that's good enough for me.","TWN":"……很好，我就要你這句話。"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"국민의 대표자로서 마리아 안토노프 중장과 델타 세븐 부대에 명령하겠네.","JPN":"国民の代表としてマリア・アントノフ中将及びデルタセブンに命ずる。","ENG":"As the representative of the people, I hereby command Lieutenant General Maria Antonov and Delta Seven unit.","TWN":"我以國家統治者的身分，授予瑪麗亞·安東諾夫中將和第七三角洲部隊國家軍權，"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"무제한 자율작전권을 부여할 테니, 인류를 위해 싸워 주도록.","JPN":"無制限の自律作戦権を与える。人類のために戦ってくれ。","ENG":"I give you full operational autonomy to defend the realms and fight for humanity.","TWN":"命令你們為人類而戰！"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"감사합니다.","JPN":"ありがとうございます。","ENG":"Thank you, sir.","TWN":"謝謝總統。"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"일이 끝나면 겸사겸사 나도 구하러 와 주고 말이지.","JPN":"仕事が終わったら、ついでに私も助けに来てくれ。","ENG":"Once you’re done, drop by and save me too, will you?","TWN":"等你們事情辦完，也可以順便來救我一下。"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PRESIDENT_NPC_NULL_NULL","text":{"KOREA":"그때까지 내가 살아 있을진 모르겠지만.","JPN":"その時まで私が生きてるかは知らんがな。","ENG":"If I’m still alive by then, that is. Good luck, Delta Seven.","TWN":"雖然到時候我未必還活著。"},"stage":{"bg":"MAINSTREAM_5502010","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"……후우.","JPN":"……ふう。","ENG":"…Whew.","TWN":"……呼。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그럼 움직여 볼까.","JPN":"それでは、動いてみようか。","ENG":"Let’s get this started now.","TWN":"那就行動吧！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"실비아! 제이크 대령은 어디에 있지?","JPN":"シルビア！　ジェイク大佐はどこにいる？","ENG":"Sylvia! Where is Colonel Walker?","TWN":"希爾維亞！傑克上校人在哪？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"무기 관리실에 있어. 스톰 브링거를 재조정 중이야.","JPN":"武器の管理室にいるよ。ストームブリンガーを再調整してる。","ENG":"He’s in the armory preparing Stormbringer.","TWN":"他在武器管理室整修興風者。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"사용은 가능한가?","JPN":"使えるか？","ENG":"Is it operational?","TWN":"可以使用嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"당장은 힘들어. 워낙 험하게 사용해서 수리해야 할 부분이 많아.","JPN":"すぐには無理だよ。使い方が荒すぎて直すところがいっぱいなんだ。","ENG":"Not at the moment. It’s been used too roughly, so it needs a lot of repairs.","TWN":"目前有難度，之前用太兇，現在有很多地方需要修理。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"아쉽지만 어쩔 수 없군.","JPN":"残念だが仕方ないな。","ENG":"That’s unfortunate, but I guess I have no other choice.","TWN":"雖然很可惜，但也沒辦法。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L46_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"제이크 대령에게 출격명령을 전달하도록.","JPN":"ジェイク大佐に出撃命令を伝えてくれ。","ENG":"Tell Colonel Walker to get ready for deployment.","TWN":"告訴傑克上校，準備出擊！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그리고 방송을 연결해 주렴.","JPN":"あと、アナウンスを繋いでくれるか？","ENG":"Also, connect me to the broadcast system.","TWN":"另外我有話要通知大家。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"알겠어, 지금 연결할게!","JPN":"わかった、今繋ぐね！","ENG":"Copy that, connecting right now!","TWN":"好，馬上準備！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>델타세븐 전 대원들에게 알린다.</color>","JPN":"<color=#ffd34c>全デルタセブンの隊員に告ぐ。</color>","ENG":"<color=#ffd34c>Alerting all Delta Seven crew members.</color>","TWN":"<color=#ffd34c>第七三角洲部隊全員注意。</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>현재 우리는 인류의 적과 결탁한 불법 쿠데타군에게 공격받고 있으며 저들은 우리 뿐 아니라 대통령과 행정부까지 무력으로 장악을 시도하고 있다.</color>","JPN":"<color=#ffd34c>現在、我々は人類の敵と結託した不法クーデター軍に攻撃されている。加えてあの者たちは我々だけでなく、大統領と行政府まで武力掌握しようとしている。</color>","ENG":"<color=#ffd34c>We are currently under attack by instigators of a coup who have aligned themselves with enemies of humanity. They are attempting to eliminate not only us, but also the President and the administrative office.</color>","TWN":"<color=#ffd34c>目前與勾結敵人的叛軍正在攻擊我們，不僅如此，他們也正企圖以武力控制總統和行政院。</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>나는 군인으로서 국민의 선택을 받은 정통성 있는 대통령의 명령에 따라 이들의 준동을 제압하고 인류의 생존을 위한 작전에 나서기로 했다.</color>","JPN":"<color=#ffd34c>私は軍人として、国民に選ばれた正統な大統領閣下の命令に従い、彼らの動きを制圧し、人類の生存のための作戦を行うことにした。</color>","ENG":"<color=#ffd34c>As a soldier, upon the orders of the President, who was been lawfully appointed by the people, I will put an end to their schemes and fight for humanity’s survival.</color>","TWN":"<color=#ffd34c>我身為一位軍人，決定奉國民選出的總統之命，鎮壓敵人，為人類的生存而戰。</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>그에 따라 지금부터 아군을 공격 중인 불법 쿠데타군에게 반격을 개시한다.</color>","JPN":"<color=#ffd34c>よって、現時点から味方を攻撃している不法クーデター軍に反撃を開始する。</color>","ENG":"<color=#ffd34c>As such, I am giving the command to launch a counteroffensive against the coup d'état forces who dare attack our own.</color>","TWN":"<color=#ffd34c>因此，現在就開始反擊攻擊我方部隊的叛軍。</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>놈들에게 따끔한 맛을 보여 주자.</color>","JPN":"<color=#ffd34c>奴らに目にもの見せてやろう。</color>","ENG":"<color=#ffd34c>Give them hell, Delta Seven.</color>","TWN":"<color=#ffd34c>讓那些傢伙知道我們的厲害！</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>이상.</color>","JPN":"<color=#ffd34c>以上。</color>","ENG":"<color=#ffd34c>Over and out.</color>","TWN":"<color=#ffd34c>以上。</color>"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};